define(["jquery","core/str"],function($,str){"use strict";var init=function(){$(document).on("click",".categoryname",function(e){e.preventDefault();var $category=$(this).closest(".category");var $content=$category.find("> .content");var $icon=$(this).find(".category-toggle-icon");if($category.hasClass("with_children")){if($category.hasClass("collapsed")){$category.removeClass("collapsed");$content.slideDown(300);$icon.removeClass("collapsed");$icon.attr("data-toggle","collapse");str.get_string("collapse","moodle").done(function(s){$icon.attr("title",s)})}else{$category.addClass("collapsed");$content.slideUp(300);$icon.addClass("collapsed");$icon.attr("data-toggle","expand");str.get_string("expand","moodle").done(function(s){$icon.attr("title",s)})}}});$(document).on("click",'[data-action="toggle-all-categories"]',function(e){e.preventDefault();var $link=$(this);var $tree=$link.closest(".course_category_tree");var $categories=$tree.find(".category.with_children");if($link.hasClass("collapse-all")){$categories.addClass("collapsed");$categories.find("> .content").slideUp(300);$categories.find(".category-toggle-icon").addClass("collapsed");$link.removeClass("collapse-all");str.get_string("expandall","moodle").done(function(s){$link.text(s)})}else{$categories.removeClass("collapsed");$categories.find("> .content").slideDown(300);$categories.find(".category-toggle-icon").removeClass("collapsed");$link.addClass("collapse-all");str.get_string("collapseall","moodle").done(function(s){$link.text(s)})}});$(document).on("keydown",".categoryname",function(e){if(e.which===13||e.which===32){e.preventDefault();$(this).click()}});$(".category.with_children > .info > .categoryname").each(function(){var $this=$(this);var $category=$this.closest(".category");var categoryId=$category.data("categoryid");var contentId="category-content-"+categoryId;$this.attr({role:"button","aria-expanded":!$category.hasClass("collapsed"),"aria-controls":contentId,tabindex:"0"});$category.find("> .content").attr("id",contentId)});$(document).on("click",".categoryname",function(){var $this=$(this);var $category=$this.closest(".category");if($category.hasClass("with_children")){setTimeout(function(){$this.attr("aria-expanded",!$category.hasClass("collapsed"))},50)}});$(document).on("click",".category.notloaded > .info > .categoryname",function(){var $category=$(this).closest(".category");var $content=$category.find("> .content");if($content.is(":empty")){str.get_string("loading","moodle").done(function(s){$content.html('<div class="loading-indicator">'+s+"...</div>")})}});$(".category > .content").css({transition:"all 0.3s ease",overflow:"hidden"});$(".category.collapsed > .content").hide();$(".categoryname").hover(function(){$(this).closest(".info").addClass("hover")},function(){$(this).closest(".info").removeClass("hover")})};return{init:init}});
